import type { Browser } from 'detect-browser';
import {
  PaymentMethod,
  PaymentMethodV2Type,
} from '@app/features/types/paymentMethodTypes';
import type { YandexAdsConfigType } from '@content/scripts/yandexSearchAds/types';
import { type SupportedLanguages } from '@app/i18n/types';

export type RegionKeys = 'base' | 'eu';
type RegionUrls = Record<RegionKeys, string>;

type LocalizedField = Record<SupportedLanguages, string>;

type RedButtonType = Record<'ru' | 'en', { url: string; text: string }>;

interface ProfileAdvertising {
  title?: LocalizedField;
  subtitle?: LocalizedField;
  img?: LocalizedField;
}

export type MetaApiData = {
  apiBaseUrl: string;
  cookieDomain: string;
  availableAlarmTries: number;
  showOnUpdateVersion?: string;
  currentVersion: string;
  requiredVersion: string;
  supportedBrowsers: Browser[];
  proxyUpdatePeriod?: number;
  shouldUpdatePAC?: string;
  shouldUpdatePACVersion?: string;
  availableBannersData?: string;
  androidAppUrl?: string;
  availablePaymentMethods?: PaymentMethod[];
  availablePaymentMethodsV2?: PaymentMethodV2Type[];
  availablePaymentMethodsV3?: PaymentMethodV2Type[];
  publicOfferUrl?: string;
  /**
   *  @deprecated использовать mediaMaxVersionChrome или mediaMaxVersionFirefox
   * */
  mediaMinVersion?: string;
  mediaMaxVersionChrome?: string;
  mediaMaxVersionFirefox?: string;
  updateSubscriptionInfoPeriod?: number;
  bannerUrls?: RegionUrls;
  bannerUrlsSecondary?: RegionUrls;
  giftsAvailableDates?: [string, string];
  giftsPeriodInMinutes?: number;
  checkProxyAvailabilityProxyUrl?: string;
  checkProxyAvailabilityPublicUrl?: string;
  subscriptionExpiringAlerts?: {
    firstTimingInMinutes?: number;
    secondTimingInMinutes?: number;
    delayedTimingInMinutes?: number;
  };
  premiumBannerPeriodInMinutes?: number;
  sidebarMediaUrl?: RegionUrls;
  beforeStartMediaIntervalInMinutes?: number;
  beforeStartMediaUrls?: RegionUrls;
  midpointMediaIntervalInMinutes?: number;
  midpointMediaUrls?: RegionUrls;
  rubleToEuroRate?: number;
  yandexConfig?: YandexAdsConfigType;
  peremenProfileBlock?: ProfileAdvertising;
  feedbackUrl?: string;
  exchangeRatesUpdatePeriodInMinutes?: number;
  redButton?: RedButtonType;
};

export interface SessionDataType {
  timestamp: number;
  session_id: string;
}

export enum ExpirableStorageKey {
  IsProxyControlledByOtherExtensions = 'isProxyControlledByOtherExtensions',
  IsAdBlockersWork = 'isAdBlockersWork',
  PopupWasOpened = 'popupWasOpened',
  MetaApiData = 'metaApiData',
  IsNetworkError = 'isNetworkError',
  isNetworkErrorHandlingInProgress = 'isNetworkErrorHandlingInProgress',
  LastProxyHost = 'lastProxyHost',
  LastProxyPort = 'lastProxyPort',
  IsInitialized = 'isInitialized',
  RequestBlockedError = 'requestBlockedError',
  UpdateSubscriptionInfoPeriod = 'updateSubscriptionInfoPeriod',
  email = 'email',
  SessionData = 'sessionData',
  MetaApiDataLastUpdatedMs = 'metaApiDataLastUpdatedMs',
  ResendEmailTimerEndsAt = 'resendEmailTimerEndsAt',
}

export type ExpirableData = {
  [ExpirableStorageKey.IsProxyControlledByOtherExtensions]?: boolean;
  [ExpirableStorageKey.IsAdBlockersWork]?: boolean;
  [ExpirableStorageKey.PopupWasOpened]?: boolean;
  [ExpirableStorageKey.MetaApiData]?: MetaApiData;
  [ExpirableStorageKey.IsNetworkError]?: boolean;
  [ExpirableStorageKey.LastProxyHost]?: string;
  [ExpirableStorageKey.LastProxyPort]?: number;
  [ExpirableStorageKey.IsInitialized]?: boolean;
  [ExpirableStorageKey.RequestBlockedError]?: string;
  [ExpirableStorageKey.UpdateSubscriptionInfoPeriod]?: number;
  [ExpirableStorageKey.email]?: string | null;
  [ExpirableStorageKey.ResendEmailTimerEndsAt]?: number | null;
  [ExpirableStorageKey.SessionData]?: SessionDataType;
  [ExpirableStorageKey.isNetworkErrorHandlingInProgress]?: boolean;
  [ExpirableStorageKey.MetaApiDataLastUpdatedMs]?: number;
};
